export const MEMBERSHIP_CSS_SOURCE = String.raw`:root{--mem-blue:#2563eb;--mem-navy:#0f172a;--mem-ink:#172033;--mem-muted:#667085;--mem-line:#dfe5ee;--mem-soft:#f5f7fb;--mem-white:#fff;--mem-radius:24px}.mmg-membership{color:var(--mem-ink);font-family:var(--font-body-family,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif)}.mmg-membership *{box-sizing:border-box}.mmg-membership h1,.mmg-membership h2,.mmg-membership h3{font-family:var(--font-heading-family,var(--font-body-family,system-ui));letter-spacing:-.04em;color:var(--mem-ink);margin-top:0}.mmg-membership h1{font-size:clamp(3.5rem,7vw,6.8rem);line-height:.96;max-width:11ch;margin-bottom:1.5rem}.mmg-membership h2{font-size:clamp(2.4rem,4.8vw,4.4rem);line-height:1.02}.mmg-membership h3{font-size:clamp(1.35rem,2vw,1.8rem);line-height:1.12}.mmg-membership p{font-size:1.08rem;line-height:1.72;color:var(--mem-muted)}.membership-shell{width:min(1180px,calc(100% - 40px));margin:auto}.membership-hero{padding:clamp(5rem,9vw,8rem) 0;background:linear-gradient(180deg,#fff,#f7f9fc);border-bottom:1px solid var(--mem-line)}.membership-hero__grid,.membership-split{display:grid;grid-template-columns:1.15fr .85fr;gap:clamp(3rem,7vw,7rem);align-items:center}.membership-lead{font-size:clamp(1.25rem,2vw,1.6rem)!important;max-width:780px;color:var(--mem-ink)!important}.membership-eyebrow{display:inline-flex;font-size:.78rem!important;font-weight:850;letter-spacing:.13em;text-transform:uppercase;color:var(--mem-blue)!important;background:#eaf1ff;border-radius:999px;padding:.62rem .9rem}.membership-actions{display:flex;flex-wrap:wrap;gap:.8rem;margin-top:2rem}.membership-actions--center{justify-content:center}.membership-button{display:inline-flex;align-items:center;justify-content:center;min-height:52px;padding:.85rem 1.4rem;border:1px solid var(--mem-line);border-radius:999px;background:#fff;color:var(--mem-ink);font-weight:820;text-decoration:none}.membership-button--primary{background:var(--mem-blue);border-color:var(--mem-blue);color:#fff}.membership-summary,.membership-portal-card,.membership-window{background:#fff;border:1px solid var(--mem-line);border-radius:30px;padding:2.2rem;box-shadow:0 20px 60px rgba(15,23,42,.09)}.membership-summary>span,.membership-card>span,.membership-window>span{font-size:.78rem;font-weight:850;letter-spacing:.09em;text-transform:uppercase;color:var(--mem-blue)}.membership-section{padding:clamp(5rem,9vw,8rem) 0}.membership-section--soft{background:var(--mem-soft);border-block:1px solid var(--mem-line)}.membership-process{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;margin-top:3rem}.membership-process article,.membership-card,.membership-library article{background:#fff;border:1px solid var(--mem-line);border-radius:var(--mem-radius);padding:1.7rem}.membership-process b{color:var(--mem-blue);font-size:.82rem}.membership-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;margin-top:3rem}.membership-card{min-height:470px;display:flex;flex-direction:column}.membership-card--featured{background:linear-gradient(145deg,#eff5ff,#fff);border-color:#b8ccff;transform:translateY(-12px)}.membership-card ul,.membership-portal-card ul{padding-left:1.2rem;color:var(--mem-muted);line-height:1.9}.membership-card a{margin-top:auto;color:var(--mem-blue);font-weight:820;text-decoration:none}.membership-section--dark{background:linear-gradient(145deg,#1d4ed8,#0f172a)}.membership-section--dark h2,.membership-section--dark p{color:#fff}.membership-section--dark .membership-eyebrow{background:rgba(255,255,255,.14);color:#fff!important}.membership-profile,.membership-library{display:grid;gap:.85rem}.membership-profile article{background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.16);border-radius:18px;padding:1.15rem}.membership-profile strong,.membership-profile span,.membership-library strong,.membership-library span{display:block}.membership-profile strong,.membership-profile span{color:#fff}.membership-profile span,.membership-library span{font-size:.85rem;margin-top:.25rem;opacity:.78}.membership-library article{padding:1.2rem}.membership-window>div{display:flex;gap:.6rem;flex-wrap:wrap;margin-top:1rem}.membership-window b{background:var(--mem-soft);border-radius:999px;padding:.45rem .7rem;font-size:.78rem}.membership-final{text-align:center;padding:clamp(5rem,9vw,8rem) 0}.membership-final h2,.membership-final>div>p:not(.membership-eyebrow){max-width:850px;margin-inline:auto}@media(max-width:900px){.membership-hero__grid,.membership-split{grid-template-columns:1fr}.membership-process{grid-template-columns:repeat(2,1fr)}.membership-grid{grid-template-columns:1fr}.membership-card--featured{transform:none}}@media(max-width:640px){.membership-shell{width:min(100% - 28px,1180px)}.membership-process{grid-template-columns:1fr}.mmg-membership h1{font-size:clamp(3rem,15vw,4.8rem)}.membership-actions .membership-button{width:100%}}`;